"""A simple in-memory cache used across the app."""


class Cache:
    def __init__(self):
        self._store = {}

    def get(self, key):
        return self._store.get(key)

    def put(self, key, value):
        self._store[key] = value

    def clear(self):
        self._store.clear()

scratch_files.app.py:
"""Toy app that leans on the cache for expensive lookups."""
from cache import Cache

_cache = Cache()


def expensive_lookup(user_id):
    hit = _cache.get(user_id)
    if hit is not None:
        return hit
    result = {"user_id": user_id, "profile": f"profile-for-{user_id}"}
    _cache.put(user_id, result)
    return result


def handle_request(user_id):
    return expensive_lookup(user_id)
